=== fallback.py 接口设计 ===

```python
class FallbackEngine:
    def __init__(self, config: dict):
        self._templates = config.get("fallback_templates", {})
        self._default = config.get("fallback_templates", {}) \
            .get("_default", {})

    def generate(self, action_type: str, intent: str,
                 context: dict | None = None) -> dict:
        \"\"\"生成 fallback 回复 payload.\"\"\"
        # 1. 精确匹配: intent 在模板中
        at_templates = self._templates.get(action_type, {})
        if intent in at_templates:
            return self._render(at_templates[intent], context)
        # 2. 关键词匹配: intent 包含模板 key
        for key, tmpl in at_templates.items():
            if key != "_default" and key in intent:
                return self._render(tmpl, context)
        # 3. 兜底: action_type 的 default
        if "_default" in at_templates:
            return self._render(at_templates["_default"], context)
        # 4. 最终兜底: 通用教学语句
        return self._render({
            "statement": "这个问题很好。让我一步步帮你理解。",
            "steps": ["先了解基本概念", "再看具体例子", "最后动手练习"],
            "question": "你想从哪个部分开始？",
        }, context)

    @staticmethod
    def _render(template: dict, context: dict | None = None) -> dict:
        \"\"\"渲染模板，返回标准 payload.\"\"\"
        return {
            "statement": template.get("statement", ""),
            "steps": template.get("steps", []),
            "question": template.get("question", ""),
            "option": template.get("option", ""),
            "hint": template.get("hint", ""),
        }
```

=== composer.py 修改 ===

```python
from src.coach.fallback import FallbackEngine

class PolicyComposer:
    def __init__(self, rules=None):
        self._rules = rules if rules is not None else _RULES
        self._fallback = FallbackEngine(_DEFAULTS)
        ...

    @staticmethod
    def _build_payload(action_type, intent) -> dict:
        # 改为调用 FallbackEngine
        fallback = FallbackEngine(_DEFAULTS)
        return fallback.generate(action_type, intent)
```

注意：_build_payload 是 static method，需要改为实例方法或内部创建 FallbackEngine。
推荐：在 compose() 中调用 self._fallback.generate() 替代 _build_payload()。

=== agent.py 修改 ===

在 act() 的 LLM 生成部分（line 544-625），当 LLM 失败或禁用时：

```python
if llm_generated:
    # ... 现有 LLM 流程 ...
else:
    # 使用 FallbackEngine 生成教学内容
    action["payload"] = self.composer._fallback.generate(
        action_type=action.get("action_type", "suggest"),
        intent=intent,
        context={"prev_statement": ctx.get("prev_statement")},
    )
```
